+        let content: Content?
+        let finishReason: String?
+    }
+
+    struct UsageMetadata: Decodable {
+        let promptTokenCount: Int?
+        let candidatesTokenCount: Int?
+        let totalTokenCount: Int?
+    }
+
+    let candidates: [Candidate]?
+    let usageMetadata: UsageMetadata?
